import { Request, Response } from 'express';
import { Status, Messages } from '../common/constants';

import { JobSite, IJobSite } from '../models/JobSite';
import { JobLocation } from '../models/JobLocation';
import * as Sentry from '@sentry/node';
import escapeStringRegexp from 'escape-string-regexp';
import { Types } from 'mongoose';

const hasValue = (value: any): boolean => value !== undefined && value !== null && String(value).trim() !== '';

const getCoordinates = (location: any): { lat: any, long: any } | null => {
    if (!location || typeof location !== 'object') {
        return null;
    }

    const lat = location.lat ?? location.latitude;
    const long = location.long ?? location.lng ?? location.longitude;

    if (!hasValue(lat) || !hasValue(long)) {
        return null;
    }

    return { lat, long };
};

const getAddress = (params: any): any => {
    if (params.address !== undefined) {
        return params.address;
    }

    return {
        street: params.street,
        city: params.city,
        state: params.state,
        zipcode: params.zipcode
    };
};

const hasAddressData = (address: any): boolean => {
    if (!address || typeof address !== 'object') {
        return false;
    }

    return ['street', 'city', 'state', 'zipcode', 'zipCode'].some((key: string) => hasValue(address[key]));
};

const getFirstId = (value: any): any => Array.isArray(value) ? value[0] : value;

const getOwnershipFromJobLocation = (jobLocation: any): { customerId?: any, homeOwner?: any } => {
    const customerId = getFirstId(jobLocation?.customerIds) || jobLocation?.customerId;
    const homeOwner = jobLocation?.homeOwner || jobLocation?.homeOwnerId;

    const ownership: { customerId?: any, homeOwner?: any } = {};
    if (customerId) {
        ownership.customerId = customerId;
    }
    if (homeOwner) {
        ownership.homeOwner = homeOwner;
    }

    return ownership;
};

export const get = async (req: Request, res: Response) => {
    const { id } = req.params;
    const { query: queryParams = {} } = req;
    const { customerId, homeOwnerId, locationId, isActive } = queryParams;

    console.log('Query Params:', queryParams);

    let query: {
        _id?: string;
        customerId?: string;
        locationId?: Types.ObjectId;
        homeOwner?: string;
        $or?: Array<{[key: string]: any}>;
        isActive?: boolean;
    } = {};

    if (id) {
        query = { _id: id };
    } else if (customerId && locationId) {
        query = { customerId, locationId: new Types.ObjectId(locationId) };
    } else if (homeOwnerId && locationId) {
        query = { homeOwner: homeOwnerId, locationId: new Types.ObjectId(locationId) };
    } else if (customerId && !homeOwnerId) {
        query = { customerId };
    } else if (customerId && homeOwnerId) {
        query = { $or: [{ customerId }, { homeOwner: homeOwnerId }] };
    } else if (homeOwnerId && !customerId) {
        query = { homeOwner: homeOwnerId };
    } else if (locationId) {
        query = { locationId: new Types.ObjectId(locationId) };
    } 

    switch (isActive) {
    case 'true':
    case true:
        query = {...query, $or: [...(query.$or || []), { isActive: true }, { isActive: { $exists: false } }] };
        break;
    case 'false':
    case false:
        query = {...query, isActive: false};
        break;
    default:
        // Retrieve all job sites
        break;
    }

    try {
        const jobSites = await JobSite.find(query).lean();
        res.status(Status.OK).json(jobSites);
    } catch (err) {
        console.error('Error in get JobSite:', err);
        res.status(Status.InternalError).json({ status: Status.Error, message: Messages.InternalServerError });
    }
};

export const create = async (req: Request, res: Response) => {
    const params = req.body || {};
    const {
        name,
        locationId,
    } = params;
    const coordinates = getCoordinates(params.location);
    const address = getAddress(params);

    // Validate required parameters
    const missingParams = [];
    if (!hasValue(name)) missingParams.push('name');
    if (!locationId) missingParams.push('locationId');

    if (missingParams.length > 0) {
        const message = `${Messages.MissingParams}: ${missingParams.join(', ')}`;
        return res.status(Status.MissingParameters).json({ status: Status.Error, message });
    }

    if (!coordinates && !hasAddressData(address)) {
        return res.status(Status.MissingParameters).json({ status: Status.Error, message: 'Either location or address is required.' });
    }

    try {
        // Find the job location
        const jobLocation = await JobLocation.findById(locationId, { customerIds: 1, customerId: 1, homeOwner: 1, homeOwnerId: 1 });

        if (!jobLocation) {
            return res.status(Status.NotFound).json({ status: Status.Error, message: 'Subdivision not found.' });
        }

        const duplicateJobSite = await JobSite.findOne({ locationId, name });
        if (duplicateJobSite) {
            return res.status(Status.MissingParameters).json({ status: Status.Error, message: 'Job Address already exists in this subdivision.' });
        }

        const newJobSiteData: any = {
            name,
            locationId,
            ...getOwnershipFromJobLocation(jobLocation)
        };

        if (coordinates) {
            newJobSiteData.location = {
                coordinates: [coordinates.long, coordinates.lat]
            };
        }

        if (hasAddressData(address)) {
            newJobSiteData.address = address;
        }

        // Create the new job site
        const newJobSite: IJobSite = await JobSite.create(newJobSiteData);

        // Update the job location with the new job site
        await JobLocation.findByIdAndUpdate(locationId, {
            $push: { jobSites: newJobSite._id }
        });

        return res.status(Status.OK).json(newJobSite);

    } catch (error) {
        Sentry.captureException(error);
        console.error('Error in create job site:', error);
        return res.status(500).json({ status: Status.Error, message: Messages.InternalServerError });
    }
};

export const update = async (req: Request, res: Response) => {
    const params = req.body || {};
    const { id } = req.params;
    const {
        name,
        location,
        isActive,
        address,
        locationId,
    } = params;

    const missingParams = [];
    if (!id) missingParams.push('id');
    if (Object.prototype.hasOwnProperty.call(params, 'locationId') && !hasValue(locationId)) missingParams.push('locationId');
    const isMissingParams = missingParams.length > 0;

    if (isMissingParams) {
        const message = `${Messages.MissingParams}: ${missingParams.join(', ')}`;
        return res.json({ status: Status.Error, message });
    }

    try {
        const jobSite = await JobSite.findById(id).exec();
        if (!jobSite) {
            return res.json({ status: Status.Error, message: 'JobSite not found.' });
        }

        const isLocationIdSubmitted = Object.prototype.hasOwnProperty.call(params, 'locationId');
        const targetLocationId = isLocationIdSubmitted ? locationId : jobSite.locationId;
        const updateData: any = {};

        if (name !== undefined && name !== null && name !== jobSite.name) {
            const duplicateJobSite = await JobSite.findOne({
                _id: { $ne: id },
                locationId: targetLocationId,
                name
            });

            if (duplicateJobSite) {
                return res.status(Status.MissingParameters).json({ status: Status.Error, message: 'Job Address already exists in this subdivision.' });
            }

            updateData.name = name;
        } else if (name !== undefined && name !== null) {
            updateData.name = name;
        }

        if (location !== undefined) {
            const coordinates = getCoordinates(location);
            if (coordinates) {
                updateData.location = {
                    coordinates: [coordinates.long, coordinates.lat]
                };
            }
        }

        if (address !== undefined) {
            updateData.address = address;
        }

        if (isActive !== undefined && isActive !== null) {
            updateData.isActive = isActive === 'false'
                ? false
                : !!isActive;
        }

        if (isLocationIdSubmitted) {
            const jobLocation = await JobLocation.findById(targetLocationId, { customerIds: 1, customerId: 1, homeOwner: 1, homeOwnerId: 1 });
            if (!jobLocation) {
                return res.json({ status: Status.Error, message: 'Subdivision not found.' });
            }

            updateData.locationId = targetLocationId;
            Object.assign(updateData, getOwnershipFromJobLocation(jobLocation));
        }

        if (Object.keys(updateData).length === 0) {
            return res.json({ status: Status.OK, message: 'Job Address has been updated successfully.' });
        }

        await JobSite.updateOne({ _id: id }, { $set: updateData });
        return res.json({ status: Status.OK, message: 'Job Address has been updated successfully.' });
    } catch (err) {
        Sentry.captureException(err);
        return res.json({ status: Status.Error, message: Messages.InternalServerError });
    }
};




